/**
 * AnimatedSubtitles Component
 *
 * Renders word-by-word captions synced to the voiceover timestamps.
 * Each word pops in with a spring animation when it's spoken,
 * creating the classic TikTok / Shorts subtitle effect.
 *
 * The subtitles array is generated by the TTS service alongside
 * the voiceover audio, so this component works identically
 * regardless of what language or content the video has.
 */
import React from "react";
import {
  AbsoluteFill,
  useCurrentFrame,
  useVideoConfig,
  interpolate,
  spring,
} from "remotion";
import {
  defaultTheme,
  getLayoutConfig,
  subtitleFadeFrames,
  type SubtitleConfig,
} from "../design-system";

export interface SubtitleEntry {
  /** The word or short phrase to display */
  text: string;
  /** Start time in seconds */
  startTime: number;
  /** End time in seconds */
  endTime: number;
}

interface AnimatedSubtitlesProps {
  subtitles: SubtitleEntry[];
  isVertical: boolean;
  config?: Partial<SubtitleConfig>;
}

/**
 * Groups subtitles into chunks of N words that appear together
 * (so we don't flash a single word at a time, but 3-5 word groups)
 */
function groupSubtitles(
  subtitles: SubtitleEntry[],
  wordsPerGroup: number,
): { text: string; startTime: number; endTime: number }[] {
  const groups: { text: string; startTime: number; endTime: number }[] = [];

  for (let i = 0; i < subtitles.length; i += wordsPerGroup) {
    const chunk = subtitles.slice(i, i + wordsPerGroup);
    groups.push({
      text: chunk.map((s) => s.text).join(" "),
      startTime: chunk[0].startTime,
      endTime: chunk[chunk.length - 1].endTime,
    });
  }

  return groups;
}

export const AnimatedSubtitles: React.FC<AnimatedSubtitlesProps> = ({
  subtitles,
  isVertical,
  config: configOverrides,
}) => {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const currentTime = frame / fps;

  const theme = defaultTheme;
  const cfg = { ...theme.subtitles, ...configOverrides };
  const layout = getLayoutConfig(width, height);

  const groups = groupSubtitles(subtitles, cfg.wordsPerGroup);

  // Find the currently active group
  const activeGroup = groups.find(
    (g) => currentTime >= g.startTime && currentTime <= g.endTime,
  );

  if (!activeGroup) return null;

  // Calculate animation progress within this group
  const groupStartFrame = Math.round(activeGroup.startTime * fps);
  const localFrame = frame - groupStartFrame;
  const groupDurationFrames = (activeGroup.endTime - activeGroup.startTime) * fps;

  const scale = spring({
    frame: localFrame,
    fps,
    config: theme.animations.springs.subtitle,
  });

  const fadeFrames = subtitleFadeFrames;
  const opacity = interpolate(
    localFrame,
    [0, fadeFrames, groupDurationFrames - fadeFrames, groupDurationFrames],
    [0, 1, 1, 0],
    theme.animations.clampBoth,
  );

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        justifyContent: "center",
        alignItems: "flex-end",
        paddingBottom: layout.subtitle.paddingBottom,
        pointerEvents: "none",
      }}
    >
      <div
        style={{
          transform: `scale(${scale})`,
          opacity,
          maxWidth: layout.subtitle.maxWidth,
          textAlign: "center",
        }}
      >
        <span
          style={{
            display: "inline-block",
            color: theme.colors.text,
            fontSize: layout.subtitle.fontSize,
            fontWeight: cfg.fontWeight,
            fontFamily: theme.typography.fontFamily.fallback,
            lineHeight: theme.typography.subtitle.lineHeight,
            textTransform: cfg.textTransform,
            letterSpacing: cfg.letterSpacing,
            textShadow: cfg.shadow,
            WebkitTextStroke: cfg.stroke,
            padding: layout.subtitle.padding,
          }}
        >
          {activeGroup.text}
        </span>
      </div>
    </AbsoluteFill>
  );
};
